/*
===============================================================================
Objekt       : monitor.VW_FrameworkFeatureCatalog
Version      : 1.7.0
Stand        : 2026-07-14
Typ          : View
Zweck        : Deklarativer Katalog prüfbarer Monitoring-Datenquellen und
               Framework-Funktionsklassen für SQL Server 2019+.
Parameter    : Keine.
Resultset    : Feature-, Versions-, Berechtigungs-, Kosten- und Probe-Metadaten.
Berechtigung : SELECT auf der View. Die genannten Berechtigungen sind Hinweise;
               das Framework führt niemals GRANT, DENY oder REVOKE aus.
Sicherheit   : ProbeSqlTemplate enthält ausschließlich statische Framework-
               Definitionen. $(DATABASE) wird in der Prüf-USP mit QUOTENAME ersetzt.
Eigenlast    : Die View selbst ist konstant. Die Probe-Statements verwenden TOP(0)
               beziehungsweise reine Statusabfragen und führen keine Deep-Scans aus.
Aufruf       : SELECT * FROM monitor.VW_FrameworkFeatureCatalog;
Änderungen   : 1.7.0 - Maschinenlesbare PermissionCheckType-/PermissionName-Spalten ergänzt; freie Hinweistexte werden nur noch per Probe geprüft.
               1.6.0 - Phase-6-Quellen für Agent, Resource Governor, HA/DR, Backup, Replication, CDC und Change Tracking ergänzt.
               1.5.0 - Extended-Events-Katalog, Targetruntime, Filezugriff, Deadlocks und Blocked-Process-Reports differenziert.
               1.4.0 - Query-Store-Status, Runtime, Waits, Pläne, Forced Plans und SQL-2022-Hints getrennt katalogisiert.
               1.3.0 - Plan-Cache-, Planattribut-, Showplan-, Last-Actual- und Live-Plan-Capabilities präzisiert.
               1.2.0 - Index Operational Stats und In-Memory-OLTP-Indexnutzung ergänzt.
               1.1.0 - Phase-2-Objekt-, Statistik-, Partitions- und Columnstore-Quellen ergänzt.
               1.0.0 - Erstfassung Phase 1A.
===============================================================================
*/
CREATE OR ALTER VIEW [monitor].[VW_FrameworkFeatureCatalog]
AS
    SELECT
        [f].[FeatureOrdinal],
        [f].[FeatureCode],
        [f].[FeatureName],
        [f].[ScopeType],
        [f].[AnalysisClass],
        [f].[AnalysisLevel],
        [f].[IsResourceIntensive],
        [f].[MinimumMajorVersion],
        [f].[PermissionScopeBeforeSql2022],
        [f].[PermissionScopeFromSql2022],
        [f].[PermissionBeforeSql2022],
        [f].[PermissionFromSql2022],
        CAST(CASE WHEN [f].[PermissionBeforeSql2022] IN
          (N'VIEW SERVER STATE',N'VIEW SERVER PERFORMANCE STATE',N'VIEW DATABASE STATE',N'VIEW DATABASE PERFORMANCE STATE',N'VIEW ANY DEFINITION',N'VIEW ANY DATABASE',N'VIEW DEFINITION')
          THEN 'HAS_PERMS_BY_NAME' ELSE 'PROBE_ONLY' END AS varchar(24)) AS [PermissionCheckTypeBeforeSql2022],
        CAST(CASE WHEN [f].[PermissionBeforeSql2022] IN
          (N'VIEW SERVER STATE',N'VIEW SERVER PERFORMANCE STATE',N'VIEW DATABASE STATE',N'VIEW DATABASE PERFORMANCE STATE',N'VIEW ANY DEFINITION',N'VIEW ANY DATABASE',N'VIEW DEFINITION')
          THEN [f].[PermissionBeforeSql2022] END AS sysname) AS [PermissionNameBeforeSql2022],
        [f].[PermissionBeforeSql2022] AS [PermissionDisplayTextBeforeSql2022],
        CAST(CASE WHEN [f].[PermissionFromSql2022] IN
          (N'VIEW SERVER STATE',N'VIEW SERVER PERFORMANCE STATE',N'VIEW DATABASE STATE',N'VIEW DATABASE PERFORMANCE STATE',N'VIEW ANY DEFINITION',N'VIEW ANY DATABASE',N'VIEW DEFINITION')
